import './AnimatedProgress.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import type { AnimatedProgressProps } from './AnimatedProgress.types';

export const AnimatedProgress: FC<AnimatedProgressProps> = ({ className, ...props }) => {
	// начальные значения анимации, будут изменяться для каждой следующей пары "персиков" для создания эффекта размытого следа
	const pairStyleSettings: AnimatedProgressSettings = {
		animationDelay: 0,
		opacity: 1,
		zIndex: 20,
	};

	// шаг с которым будут изменяться стили каждого следующего шага
	const stepChanges: AnimatedProgressSettings = {
		animationDelay: 5,
		opacity: 1.18,
		zIndex: 1,
	};

	// количество пар "персиков" создающее визуальный эффект размытого следа
	const pairsAmount = 20;

	// данные стилей для каждой пары
	const pairsData: AnimatedProgressSettings[] = [];

	for (let pairs = 0; pairs <= pairsAmount; pairs++) {
		// наполняем массив, клонируя объект настроек
		pairsData.push({ ...pairStyleSettings });

		// изменяем текущие настройки на один шаг
		pairStyleSettings.animationDelay += stepChanges.animationDelay;
		pairStyleSettings.opacity /= stepChanges.opacity;
		// pairStyleSettings.zIndex -= stepChanges.zIndex;
	}

	return (
		<span
			data-testid="AnimatedProgress"
			className={classNames('dsb-progress-animated', className)}
			{...props}
			role="progressbar"
		>
			{pairsData.map((data, i) => (
				<div
					key={i}
					className="dsb-progress-animated__pair"
					style={{
						animationDelay: data.animationDelay + 'ms',
						opacity: data.opacity,
						zIndex: data.zIndex,
					}}
				>
					<span className="dsb-progress-animated__circle" />
					<span className="dsb-progress-animated__circle" />
				</div>
			))}
		</span>
	);
};

/**
 * настройки для создания анимации с эффектом размытого следа
 */
interface AnimatedProgressSettings {
	/**
	 * задержка старта анимации каждого элемента создает след
	 */
	animationDelay: number;
	/**
	 * прозрачность каждого элемента создает размытость
	 */
	opacity: number;
	/**
	 * положение по оси z позволяет сохранить правильный цвет фона
	 */
	zIndex: number;
}
